// frontend/src/pages/Timeline.js
import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function Timeline() {
  const navigate = useNavigate();

  const goToGame = (lessonId) => {
    navigate(`/play/${lessonId}`);
  };

  return (
    <div className="p-8 bg-yellow-50 min-h-screen flex flex-col items-center">
      <h1 className="text-3xl font-bold text-red-900 mb-2">Dòng Chảy Thời Gian ⛵</h1>
      <p className="mb-8 text-gray-700 italic">Hãy ghé qua các bến đỗ để thu thập kiến thức nhé!</p>
      
      <div className="flex flex-col gap-4 w-full max-w-md">
        <button onClick={() => goToGame('dinh')} className="bg-amber-700 hover:bg-amber-800 text-white p-4 rounded-lg shadow-md text-xl font-semibold transform hover:scale-105 transition">1. Triều Đinh</button>
        <button onClick={() => goToGame('tien-le')} className="bg-amber-700 hover:bg-amber-800 text-white p-4 rounded-lg shadow-md text-xl font-semibold transform hover:scale-105 transition">2. Triều Tiền Lê</button>
        <button onClick={() => goToGame('ly')} className="bg-amber-700 hover:bg-amber-800 text-white p-4 rounded-lg shadow-md text-xl font-semibold transform hover:scale-105 transition">3. Triều Lý</button>
      </div>
      
      <button onClick={() => navigate('/leaderboard')} className="mt-10 text-red-800 font-bold underline">
        Xem Bảng Phong Thần
      </button>
    </div>
  );
}
